{"command": "python3 << 'EOF'
import requests

headers = {
    'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36'
}

# Try PWT 10.0 download
url = "https://www.rug.nl/ggdc/productivity/pwt/pwt-releases/pwt100/data/pwt100.xlsx"
try:
    r = requests.get(url, headers=headers, timeout=10)
    print("PWT status:", r.status_code)
    if r.status_code == 200:
        with open('pwt100.xlsx', 'wb') as f:
            f.write(r.content)
        print("Downloaded PWT, size:", len(r.content))
except Exception as e:
    print("PWT error:", e)

# Try WEO data
url2 = "https://www.imf.org/external/pubs/ft/weo/2025/01/weodata/WEOApr2025all.xlsx"
try:
    r2 = requests.get(url2, headers=headers, timeout=10)
    print("WEO status:", r2.status_code)
    if r2.status_code == 200:
        with open('weo.xlsx', 'wb') as f:
            f.write(r2.content)
        print("Downloaded WEO, size:", len(r2.content))
except Exception as e:
    print("WEO error:", e)
EOF", "description": "Download PWT and WEO with requests and user agent", "timeout": 30000}

